usage.programmatic:
import { WcContextMenu } from './wc-context-menu.js';

element.addEventListener('contextmenu', (e) => {
  e.preventDefault();
  WcContextMenu.show(e.clientX, e.clientY, [
    { label: 'Edit', icon: 'pen', action: () => edit() },
    { divider: true },
    { label: 'Delete', icon: 'trash', action: () => remove(), disabled: true },
  ]);
});

patterns.notificationPattern:
// Success notification
wc.Notify.showSuccess('Record saved successfully!', 3000);

// Error notification
wc.Notify.showError('Failed to save record.', 5000, true);

// Confirmation dialog
wc.Prompt.question({
  title: 'Delete Record?',
  text: 'This action cannot be undone.',
  callback: (result) => {
    if (result.isConfirmed) {
      // proceed with delete
    }
  }
});
